from solution import solve

def test_shortest_path_and_tie_order():
    assert solve({'a': ['b', 'c'], 'b': ['d'], 'c': ['d']}, 'a', 'd') == ['a', 'b', 'd']

def test_unreachable_and_same_node():
    assert solve({'a': []}, 'a', 'z') == []
    assert solve({}, 'x', 'x') == ['x']
